SELECT SUM(ballots_cast) AS total_ballots_cast
FROM ballots_cast
WHERE election_id = 1;

SELECT AVG(avg_voter_turnout) AS overall_avg_voter_turnout
FROM (
    SELECT county_id, AVG(voter_turnout) AS avg_voter_turnout
    FROM results
    GROUP BY county_id
) AS county_turnout;

SELECT precinct_name
FROM precincts
WHERE precinct_voter_registration = (
  SELECT MAX(precinct_voter_registration) 
  FROM precincts
);

SELECT county_name 
FROM counties 
ORDER BY county_name;

SELECT voter_turnout
FROM ballots_cast
WHERE election_id = 1 AND county_id = 0;

SELECT SUM(votes) AS total_straight_party_votes
FROM straight_party_votes
WHERE election_id = 0 AND party_id = 1;
